 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachineInstanceMigration } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import SubTitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/SubTitleChartLabel';
 5	import TitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/TitleChartLabel';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { OnFilterChange } from '@openshift-console/dynamic-plugin-sdk';
 8	import { ChartDonut } from '@patternfly/react-charts';
 9	
10	import { colorScale } from './constants';
11	import MigrationChartLegend from './MigrationChartLegend';
12	
13	type MigrationsChartDonutProps = {
14	  onFilterChange: OnFilterChange;
15	  vmims: V1VirtualMachineInstanceMigration[];
16	};
17	
18	export type ChartDataItem = {
19	  x: string; // vmim status key
20	  y: number; // count of each status
21	};
22	
23	const MigrationsChartDonut: FC<MigrationsChartDonutProps> = ({ onFilterChange, vmims }) => {
24	  const { t } = useKubevirtTranslation();
25	
26	  if (!vmims?.length) return null;
27	
28	  const vmimsStatusCountMap = vmims?.reduce((acc, vmim) => {
29	    const vmimStatusKey = vmim?.status?.phase;
30	
31	    acc[vmimStatusKey] = acc?.[vmimStatusKey] + 1 || 1;
32	
33	    return acc;
34	  }, {} as { [status: string]: number });
35	
36	  const chartData: ChartDataItem[] = Object.entries(vmimsStatusCountMap)?.map(
37	    ([status, statusCount]) => ({
38	      x: status,
39	      y: statusCount,
40	    }),
41	  );
42	
43	  return (
44	    <>
45	      <ChartDonut
46	        ariaDesc={t('Cluster scope migrations')}
47	        ariaTitle={t('Migrations')}
48	        colorScale={colorScale}
49	        constrainToVisibleArea
50	        data={chartData}
51	        height={220}
52	        labels={({ datum }) => `${datum.x}: ${datum.y}`}
53	        legendPosition="bottom"
54	        padding={20}
55	        subTitle={t('Migrations')}
56	        subTitleComponent={<SubTitleChartLabel />}
57	        title={vmims?.length.toString()}
58	        titleComponent={<TitleChartLabel />}
59	        width={600}
60	      />
61	      <MigrationChartLegend legendItems={chartData} onFilterChange={onFilterChange} />
62	    </>
63	  );
64	};
65	
66	export default MigrationsChartDonut;

